use std::collections::{HashMap, VecDeque};
use std::sync::{Arc, Mutex};

pub struct LruCache<K: Eq + std::hash::Hash + Clone, V: Clone> {
    inner: Arc<Mutex<LruInner<K, V>>>,
}

struct LruInner<K, V> {
    map: HashMap<K, V>,
    order: VecDeque<K>,
    capacity: usize,
}

impl<K: Eq + std::hash::Hash + Clone, V: Clone> LruCache<K, V> {
    pub fn new(capacity: usize) -> Self {
        Self {
            inner: Arc::new(Mutex::new(LruInner {
                map: HashMap::new(),
                order: VecDeque::new(),
                capacity,
            })),
        }
    }

    pub fn get(&self, key: &K) -> Option<V> {
        let mut inner = self.inner.lock().unwrap();
        if let Some(val) = inner.map.get(key) {
            let val = val.clone();
            inner.order.retain(|k| k != key);
            inner.order.push_back(key.clone());
            Some(val)
        } else {
            None
        }
    }

    pub fn put(&self, key: K, value: V) {
        let mut inner = self.inner.lock().unwrap();
        if inner.map.contains_key(&key) {
            inner.order.retain(|k| k != &key);
        } else if inner.map.len() >= inner.capacity {
            if let Some(evicted) = inner.order.pop_front() {
                inner.map.remove(&evicted);
            }
        }
        inner.map.insert(key.clone(), value);
        inner.order.push_back(key);
    }
}

